'use client';

import React, { useState, useRef } from 'react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Alert } from '@/components/ui/alert';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { CheckCircle2, AlertCircle, Mic, Upload, Volume2 } from 'lucide-react';

interface AnalysisResult {
  transcript: string;
  metrics: { wordCount: number; wpm: number; pace: string };
  fillers: { total: number; breakdown: Array<{ word: string; count: number }> };
  scores: { overall: number; pronunciation: number; pace: number; fillers: number; flow: number };
  feedback: string;
  pronunciationTips: Array<{
    word: string;
    issue: string;
    phonetic?: string;
    correct?: string;
    tip?: string;
    example?: string;
    commonMistake?: string;
    audioUrl?: string;
  }>;
  avgConfidence: number;
}

export default function Page() {
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [playingWord, setPlayingWord] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  const playPronunciation = async (word: string, audioUrl?: string) => {
    if (!audioUrl) return;
    
    try {
      setPlayingWord(word);
      if (audioRef.current) {
        audioRef.current.src = audioUrl;
        await audioRef.current.play();
      }
    } catch (error) {
      console.error('Error playing audio:', error);
      setPlayingWord(null);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setLoading(true);
    try {
      const formData = new FormData();
      formData.append('audio', file);
      formData.append('scenario', 'job-interview');

      const response = await fetch('/api/analyze', {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();
      setAnalysis(data);
    } catch (error) {
      console.error('Upload failed:', error);
    } finally {
      setLoading(false);
    }
  };

  const hasSignificantIssues = analysis?.pronunciationTips && analysis.pronunciationTips.length > 0;

  return (
    <div className="min-h-screen bg-background p-6">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-4xl font-bold mb-2">Pronunciation Coach</h1>
          <p className="text-muted-foreground">Analyze your English pronunciation</p>
        </div>

        {/* Upload Section */}
        {!analysis && (
          <Card className="p-8 mb-8 border-2 border-dashed border-primary/30 hover:border-primary/50 transition-colors">
            <div className="flex flex-col items-center justify-center gap-4">
              <Mic className="w-12 h-12 text-primary" />
              <h2 className="text-xl font-semibold">Upload Your Audio</h2>
              <p className="text-sm text-muted-foreground text-center">
                Record yourself speaking and get detailed pronunciation feedback
              </p>
              <input
                ref={fileInputRef}
                type="file"
                accept="audio/*"
                onChange={handleFileUpload}
                disabled={loading}
                className="hidden"
              />
              <Button
                onClick={() => fileInputRef.current?.click()}
                disabled={loading}
                size="lg"
                className="gap-2"
              >
                <Upload className="w-4 h-4" />
                {loading ? 'Analyzing...' : 'Choose Audio File'}
              </Button>
            </div>
          </Card>
        )}

        {/* Results Section */}
        {analysis && (
          <div className="space-y-6">
            {/* Clarity Status */}
            <Card className="overflow-hidden border-l-4 border-l-green-500">
              <div className="p-6 bg-green-50/50">
                <div className="flex items-start gap-3">
                  <CheckCircle2 className="w-6 h-6 text-green-600 mt-1 flex-shrink-0" />
                  <div className="flex-1">
                    {hasSignificantIssues ? (
                      <>
                        <h3 className="font-semibold text-green-900">
                          Found {analysis.pronunciationTips.length} word{analysis.pronunciationTips.length !== 1 ? 's' : ''} to work on
                        </h3>
                        <p className="text-sm text-green-800 mt-1">
                          Overall clarity: {analysis.avgConfidence}% — Here are specific improvements to focus on.
                        </p>
                      </>
                    ) : (
                      <>
                        <h3 className="font-semibold text-green-900">
                          No significant clarity issues detected. Your words came through clearly!
                        </h3>
                        <p className="text-sm text-green-800 mt-1">
                          Overall clarity: {analysis.avgConfidence}% — Excellent pronunciation overall.
                        </p>
                      </>
                    )}
                  </div>
                </div>
              </div>
            </Card>

            {/* Pronunciation Tips */}
            {hasSignificantIssues && (
              <Card>
                <div className="p-6 border-b">
                  <h3 className="font-semibold text-lg flex items-center gap-2">
                    <AlertCircle className="w-5 h-5 text-amber-600" />
                    Specific corrections based on what you said:
                  </h3>
                </div>
                <Accordion type="single" collapsible className="w-full">
                  {analysis.pronunciationTips.map((tip, idx) => (
                    <AccordionItem key={idx} value={`tip-${idx}`} className="border-b last:border-b-0">
                      <AccordionTrigger className="px-6 py-4 hover:no-underline">
                        <div className="flex items-center justify-between w-full text-left gap-3">
                          <div className="flex-1">
                            <span className="font-semibold text-amber-600">{tip.word}</span>
                            <span className="text-sm text-muted-foreground ml-3">{tip.issue}</span>
                          </div>
                          {tip.audioUrl && (
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                playPronunciation(tip.word, tip.audioUrl);
                              }}
                              className={`p-2 rounded-lg transition-colors ${
                                playingWord === tip.word
                                  ? 'bg-amber-500 text-white'
                                  : 'bg-amber-100 text-amber-700 hover:bg-amber-200'
                              }`}
                              title={`Listen to "${tip.word}" pronunciation`}
                            >
                              <Volume2 className="w-4 h-4" />
                            </button>
                          )}
                        </div>
                      </AccordionTrigger>
                      <AccordionContent className="px-6 pb-4 pt-2 space-y-3">
                        {tip.phonetic && (
                          <div>
                            <p className="text-sm font-semibold text-muted-foreground">Phonetic:</p>
                            <p className="text-base font-mono">{tip.phonetic}</p>
                          </div>
                        )}
                        {tip.correct && (
                          <div>
                            <p className="text-sm font-semibold text-muted-foreground">How to say it:</p>
                            <p className="text-base">{tip.correct}</p>
                          </div>
                        )}
                        {tip.tip && (
                          <div>
                            <p className="text-sm font-semibold text-muted-foreground">Quick tip:</p>
                            <p className="text-base">{tip.tip}</p>
                          </div>
                        )}
                        {tip.commonMistake && (
                          <div className="bg-amber-50 p-3 rounded">
                            <p className="text-sm font-semibold text-amber-900">Common mistake:</p>
                            <p className="text-sm text-amber-800">{tip.commonMistake}</p>
                          </div>
                        )}
                        {tip.example && (
                          <div>
                            <p className="text-sm font-semibold text-muted-foreground">Example:</p>
                            <p className="text-sm italic text-muted-foreground">{tip.example}</p>
                          </div>
                        )}
                      </AccordionContent>
                    </AccordionItem>
                  ))}
                </Accordion>
              </Card>
            )}

            {/* Metrics */}
            <Card>
              <div className="p-6">
                <h3 className="font-semibold text-lg mb-4">Your Metrics</h3>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                  <div>
                    <p className="text-sm text-muted-foreground">Words per minute</p>
                    <p className="text-2xl font-bold">{analysis.metrics.wpm}</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Pace</p>
                    <p className="text-2xl font-bold">{analysis.metrics.pace}</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Clarity</p>
                    <p className="text-2xl font-bold">{analysis.avgConfidence}%</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Overall Score</p>
                    <p className="text-2xl font-bold">{analysis.scores.overall}/100</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Pronunciation</p>
                    <p className="text-2xl font-bold">{analysis.scores.pronunciation}/100</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Filler words</p>
                    <p className="text-2xl font-bold">{analysis.fillers.total}</p>
                  </div>
                </div>
              </div>
            </Card>

            {/* Feedback */}
            <Card className="border-l-4 border-l-blue-500">
              <div className="p-6 bg-blue-50/30">
                <h3 className="font-semibold text-lg mb-4 flex items-center gap-2">
                  <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                  AI Coaching Feedback
                </h3>
                <div className="space-y-4">
                  {analysis.feedback.split('\n\n').map((section, idx) => {
                    const lines = section.split('\n').filter(l => l.trim());
                    const isHeader = lines[0]?.startsWith('**');
                    
                    return (
                      <div key={idx} className={isHeader ? "mt-6" : ""}>
                        {lines.map((line, lineIdx) => {
                          if (line.startsWith('**')) {
                            const headerText = line.replace(/\*\*/g, '');
                            return (
                              <h4 key={lineIdx} className="font-bold text-base text-blue-900 mb-3 uppercase tracking-wide">
                                {headerText}
                              </h4>
                            );
                          }
                          
                          if (line.startsWith('Day')) {
                            return (
                              <div key={lineIdx} className="bg-white rounded p-3 mb-2 border-l-2 border-blue-300">
                                <p className="text-sm text-foreground font-medium">{line}</p>
                              </div>
                            );
                          }
                          
                          if (line.startsWith('-') || line.startsWith('•')) {
                            return (
                              <div key={lineIdx} className="ml-4 mb-2">
                                <p className="text-sm text-foreground">{line}</p>
                              </div>
                            );
                          }
                          
                          return line ? (
                            <p key={lineIdx} className="text-sm text-foreground mb-3 leading-relaxed">
                              {line}
                            </p>
                          ) : null;
                        })}
                      </div>
                    );
                  })}
                </div>
              </div>
            </Card>

            {/* Transcript */}
            <Card>
              <div className="p-6">
                <h3 className="font-semibold text-lg mb-4">Your Transcript</h3>
                <p className="text-foreground leading-relaxed">{analysis.transcript}</p>
              </div>
            </Card>

            <Button onClick={() => setAnalysis(null)} variant="outline" className="w-full">
              Analyze Another Recording
            </Button>
          </div>
        )}
      </div>
      
      {/* Hidden audio element for pronunciation playback */}
      <audio
        ref={audioRef}
        onEnded={() => setPlayingWord(null)}
        crossOrigin="anonymous"
      />
    </div>
  );
}
